import itertools, importlib.util
spec = importlib.util.spec_from_file_location('solver', '/app/solver')
mod = importlib.util.module_from_spec(spec)
spec.loader.exec_module(mod)

# Independent forward action implementation for validation.
def apply_forward(board, action):
    arr = list(board)
    op, idx = action[0], int(action[1])
    if op == 'R':
        base = idx * 4
        row = [((arr[base + i] + 1) & 3) for i in range(4)]
        row = row[-1:] + row[:-1]
        arr[base:base+4] = row
    elif op == 'L':
        base = idx * 4
        row = arr[base:base+4]
        row = row[1:] + row[:1]
        row = [((v - 1) & 3) for v in row]
        arr[base:base+4] = row
    elif op == 'D':
        col = [((arr[r*4 + idx] + 1) & 3) for r in range(4)]
        col = col[-1:] + col[:-1]
        for r, v in enumerate(col):
            arr[r*4 + idx] = v
    elif op == 'U':
        col = [arr[r*4 + idx] for r in range(4)]
        col = col[1:] + col[:1]
        col = [((v - 1) & 3) for v in col]
        for r, v in enumerate(col):
            arr[r*4 + idx] = v
    return bytes(arr)

actions = mod.ACTION_LABELS
order = {a:i for i,a in enumerate(actions)}

def score(seq):
    switches = sum((seq[i][0] in 'LR') != (seq[i+1][0] in 'LR') for i in range(len(seq)-1))
    return (len(seq), switches, tuple(order[a] for a in seq))

# Build a validation sample of boards reachable within depth 3.
boards = {mod.ZERO_BOARD}
for depth in range(1, 4):
    for seq in itertools.product(actions, repeat=depth):
        b = mod.ZERO_BOARD
        for a in seq:
            b = apply_forward(b, a)
        boards.add(b)

best = mod.action_search(boards)
for board in boards:
    brute = None
    for depth in range(6):
        for seq in itertools.product(actions, repeat=depth):
            b = board
            for a in seq:
                b = apply_forward(b, a)
            if b == mod.ZERO_BOARD:
                cand = (score(seq), list(seq))
                if brute is None or cand[0] < brute[0]:
                    brute = cand
        if brute is not None:
            break
    got = best[board]
    seq = mod.decode_sequence(got[0], got[2])
    assert brute[1] == seq, (board, brute[1], seq)
print('validated boards:', len(boards))
